mapper.select:
SELECT
    id,
    order_id as "orderId",
    customer_id as "customerId",
    reason,
    return_type as "returnType",
    total_refund_amount as "totalRefundAmount",
    state_id as "stateId",
    created_time as "createdTime"
FROM returnrequest

    AND order_id = #{orderId}
    AND customer_id = #{customerId}
    AND state_id = #{currentState}
    AND return_type = #{returnType}

${orderby} ${pagination}

SELECT count(*) FROM returnrequest

    AND order_id = #{orderId}
    AND customer_id = #{customerId}
    AND state_id = #{currentState}
    AND return_type = #{returnType}
